import math
from dataclasses import dataclass
from datetime import timedelta

@dataclass
class SLATarget:
    availability_pct: float
    period_days: int = 30

    @property
    def error_budget_fraction(self) -> float:
        return 1.0 - (self.availability_pct / 100.0)

    @property
    def error_budget_minutes(self) -> float:
        return self.error_budget_fraction * self.period_days * 24 * 60

    @property
    def error_budget_seconds(self) -> float:
        return self.error_budget_minutes * 60

    def burn_rate(self, observed_error_rate: float) -> float:
        if self.error_budget_fraction == 0:
            return float("inf")
        return observed_error_rate / self.error_budget_fraction

    def time_to_exhaustion(self, observed_error_rate: float) -> float:
        rate = self.burn_rate(observed_error_rate)
        if rate <= 0:
            return float("inf")
        return self.period_days / rate

    def report(self, observed_error_rate: float = 0.0) -> str:
        lines = [
            f"SLA: {self.availability_pct}%",
            f"Error budget: {self.error_budget_minutes:.1f} min/month",
            f"             ({self.error_budget_seconds:.0f} seconds)",
        ]
        if observed_error_rate > 0:
            br = self.burn_rate(observed_error_rate)
            tte = self.time_to_exhaustion(observed_error_rate)
            lines += [
                f"Observed error rate: {observed_error_rate*100:.3f}%",
                f"Burn rate: {br:.1f}x",
                f"Budget exhausted in: {tte:.1f} days (if rate persists)",
                f"Status: {'CRITICAL' if br > 5 else 'WARNING' if br > 1 else 'OK'}",
            ]
        return "
".join(lines)


class CircuitBreaker:
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

    def __init__(self, error_threshold: float, window_size: int = 100, recovery_timeout_s: int = 60):
        self.error_threshold = error_threshold
        self.window_size = window_size
        self.recovery_timeout_s = recovery_timeout_s
        self._state = self.CLOSED
        self._failures = 0
        self._successes = 0
        self._open_time: float = 0.0

    @property
    def state(self) -> str:
        return self._state

    def record_success(self) -> None:
        if self._state == self.HALF_OPEN:
            self._state = self.CLOSED
            self._failures = 0
            self._successes = 0
        elif self._state == self.CLOSED:
            self._successes += 1

    def record_failure(self) -> None:
        import time
        if self._state == self.HALF_OPEN:
            self._state = self.OPEN
            self._open_time = time.time()
            return
        self._failures += 1
        total = self._failures + self._successes
        if total >= self.window_size:
            error_rate = self._failures / total
            if error_rate >= self.error_threshold:
                self._state = self.OPEN
                self._open_time = time.time()
                print(f"Circuit OPEN: error rate {error_rate:.1%} >= threshold {self.error_threshold:.1%}")
            self._failures = 0
            self._successes = 0

    def allow_request(self) -> bool:
        import time
        if self._state == self.CLOSED:
            return True
        if self._state == self.OPEN:
            if time.time() - self._open_time > self.recovery_timeout_s:
                self._state = self.HALF_OPEN
                return True
            return False
        return True  # HALF_OPEN: allow one probe


